//! TPE cross-validation tests: verify Rust matches Python reference values exactly.
//!
//! Reference values generated by `tests/tpe_cross_validate_baseline.py`
//! and stored in `tests/tpe_baseline_values.json`.

use indexmap::IndexMap;
use std::collections::HashMap;

use optuna_rs::distributions::*;
use optuna_rs::samplers::tpe::parzen_estimator::{
    default_gamma, default_weights, ParzenEstimator, ParzenEstimatorParameters,
};
use optuna_rs::samplers::tpe::truncnorm;

const TOL: f64 = 1e-8;
const NEWTON_TOL: f64 = 1e-5;

fn load_baseline() -> serde_json::Value {
    let data = include_str!("tpe_baseline_values.json");
    serde_json::from_str(data).expect("Failed to parse tpe_baseline_values.json")
}

fn get_f64(b: &serde_json::Value, key: &str) -> f64 {
    if let Some(v) = b[key].as_f64() {
        return v;
    }
    match b[key].as_str() {
        Some("-Infinity") => f64::NEG_INFINITY,
        Some("Infinity") => f64::INFINITY,
        _ => panic!("Key '{key}' not found or not a number"),
    }
}

fn get_f64_vec(b: &serde_json::Value, key: &str) -> Vec<f64> {
    b[key]
        .as_array()
        .unwrap_or_else(|| panic!("Key '{key}' not an array"))
        .iter()
        .map(|v| v.as_f64().unwrap())
        .collect()
}

fn assert_close(actual: f64, expected: f64, tol: f64, msg: &str) {
    if expected.is_infinite() {
        assert!(
            actual.is_infinite() && actual.signum() == expected.signum(),
            "{msg}: expected {expected}, got {actual}"
        );
        return;
    }
    if expected.is_nan() {
        assert!(actual.is_nan(), "{msg}: expected NaN, got {actual}");
        return;
    }
    let diff = (actual - expected).abs();
    let denom = expected.abs().max(1.0);
    assert!(
        diff / denom < tol,
        "{msg}: expected {expected}, got {actual}, diff={diff}"
    );
}

fn assert_vec_close(actual: &[f64], expected: &[f64], tol: f64, msg: &str) {
    assert_eq!(actual.len(), expected.len(), "{msg}: length {}, expected {}", actual.len(), expected.len());
    for (i, (&a, &e)) in actual.iter().zip(expected.iter()).enumerate() {
        assert_close(a, e, tol, &format!("{msg}[{i}]"));
    }
}

fn default_pe_params() -> ParzenEstimatorParameters {
    ParzenEstimatorParameters::default()
}

fn float_search_space(low: f64, high: f64, log: bool) -> IndexMap<String, Distribution> {
    let mut ss = IndexMap::new();
    ss.insert(
        "x".to_string(),
        Distribution::FloatDistribution(FloatDistribution::new(low, high, log, None).unwrap()),
    );
    ss
}

// ═══════════════════════════════════════════════════════════════════════════
//  1. ndtr — Normal CDF (including erfc-critical region)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_ndtr() {
    let b = load_baseline();
    let cases: &[(f64, &str)] = &[
        (-6.0, "ndtr_-6.0"),
        (-3.0, "ndtr_-3.0"),
        (-1.0, "ndtr_-1.0"),
        (0.0, "ndtr_0.0"),
        (1.0, "ndtr_1.0"),
        (3.0, "ndtr_3.0"),
        (6.0, "ndtr_6.0"),
    ];
    for &(x, key) in cases {
        let py = get_f64(&b, key);
        let rust = 0.5 + 0.5 * libm::erf(x * std::f64::consts::FRAC_1_SQRT_2);
        assert_close(rust, py, TOL, &format!("ndtr({x})"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  1b. log_ndtr — Log Normal CDF precision
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_log_ndtr() {
    let b = load_baseline();
    let cases: &[(f64, &str)] = &[
        (-40.0, "log_ndtr_-40.0"),
        (-20.0, "log_ndtr_-20.0"),
        (-10.0, "log_ndtr_-10.0"),
        (-5.0, "log_ndtr_-5.0"),
        (-3.0, "log_ndtr_-3.0"),
        (-1.0, "log_ndtr_-1.0"),
        (0.0, "log_ndtr_0.0"),
        (1.0, "log_ndtr_1.0"),
        (3.0, "log_ndtr_3.0"),
        (6.0, "log_ndtr_6.0"),
        (10.0, "log_ndtr_10.0"),
    ];
    for &(x, key) in cases {
        let py = get_f64(&b, key);
        // log_ndtr is private, verify via log_gauss_mass(-inf, x) ≈ log_ndtr(x)
        // For very negative lower bound, log_gauss_mass(a, x) → log_ndtr(x)
        let rust = truncnorm::log_gauss_mass(-1e10, x);
        assert_close(rust, py, TOL, &format!("log_ndtr({x})"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  2. log_gauss_mass
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_log_gauss_mass() {
    let b = load_baseline();
    let cases: &[(f64, f64, &str)] = &[
        (-10.0, 10.0, "log_gauss_mass_-10.0_10.0"),
        (-10.0, 0.0, "log_gauss_mass_-10.0_0.0"),
        (0.0, 10.0, "log_gauss_mass_0.0_10.0"),
        (-1.0, 1.0, "log_gauss_mass_-1.0_1.0"),
        (-2.0, 2.0, "log_gauss_mass_-2.0_2.0"),
        (-3.0, -2.0, "log_gauss_mass_-3.0_-2.0"),
        (2.0, 3.0, "log_gauss_mass_2.0_3.0"),
        (-0.5, 0.5, "log_gauss_mass_-0.5_0.5"),
        (-30.0, -20.0, "log_gauss_mass_-30.0_-20.0"),
        (20.0, 30.0, "log_gauss_mass_20.0_30.0"),
        (-0.01, 0.01, "log_gauss_mass_-0.01_0.01"),
    ];
    for &(a, bb, key) in cases {
        let py = get_f64(&b, key);
        let rust = truncnorm::log_gauss_mass(a, bb);
        assert_close(rust, py, TOL, &format!("log_gauss_mass({a},{bb})"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  3. truncnorm logpdf
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_truncnorm_logpdf() {
    let b = load_baseline();
    // (x, a, b, loc, scale)
    let cases: &[(f64, f64, f64, f64, f64)] = &[
        (0.0, -1.0, 1.0, 0.0, 1.0),
        (0.5, -2.0, 2.0, 0.0, 1.0),
        (-0.5, -2.0, 2.0, 0.0, 1.0),
        (0.0, -10.0, 10.0, 0.0, 1.0),
        (5.0, 0.0, 10.0, 3.0, 2.0),
        (0.1, 0.0, 1.0, 0.5, 0.3),
        (0.99, 0.0, 1.0, 0.5, 0.3),
        (2.0, -1.0, 1.0, 0.0, 1.0),  // out of range
        (-2.0, -1.0, 1.0, 0.0, 1.0), // out of range
    ];
    for (i, &(x, a, bb, loc, scale)) in cases.iter().enumerate() {
        let key = format!("tn_logpdf_{i}");
        let py = get_f64(&b, &key);
        let rust = truncnorm::logpdf(x, a, bb, loc, scale);
        assert_close(rust, py, TOL, &format!("logpdf({x},[{a},{bb}],loc={loc},s={scale})"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  4. truncnorm PPF (percent point function / quantile)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_truncnorm_ppf() {
    let b = load_baseline();
    // (q, a, b) — standardized (loc=0, scale=1)
    let cases: &[(f64, f64, f64)] = &[
        (0.0, -2.0, 2.0), (0.5, -2.0, 2.0), (1.0, -2.0, 2.0),
        (0.1, -1.0, 1.0), (0.25, -1.0, 1.0), (0.75, -1.0, 1.0), (0.9, -1.0, 1.0),
        (0.5, -10.0, 10.0), (0.01, -3.0, 3.0), (0.99, -3.0, 3.0),
        (0.5, 0.0, 5.0), (0.1, 1.0, 3.0), (0.9, 1.0, 3.0),
        (0.5, -5.0, 0.0), (0.1, -3.0, -1.0), (0.9, -3.0, -1.0),
        (0.001, -5.0, 5.0), (0.999, -5.0, 5.0),
    ];
    for (i, &(q, a, bb)) in cases.iter().enumerate() {
        let key = format!("tn_ppf_{i}");
        let py = get_f64(&b, &key);
        let rust = truncnorm::ppf(q, a, bb);
        assert_close(rust, py, NEWTON_TOL, &format!("ppf({q},{a},{bb})"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  5. ParzenEstimator — float kernels (mus, sigmas, weights)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_pe_float_kernels() {
    let b = load_baseline();
    let ss = float_search_space(0.0, 10.0, false);
    let mut obs = HashMap::new();
    obs.insert("x".to_string(), vec![2.0, 5.0, 8.0]);
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    // Weights
    let py_w = get_f64_vec(&b, "pe_float_weights");
    assert_vec_close(pe.weights(), &py_w, TOL, "pe_float_weights");

    // Mus & sigmas
    let (mus, sigmas, _, _) = pe.numerical_kernels("x").unwrap();
    let py_mus = get_f64_vec(&b, "pe_float_mus");
    let py_sig = get_f64_vec(&b, "pe_float_sigmas");
    assert_vec_close(&mus, &py_mus, TOL, "pe_float_mus");
    assert_vec_close(&sigmas, &py_sig, TOL, "pe_float_sigmas");
}

#[test]
fn cv_pe_float_empty() {
    let b = load_baseline();
    let ss = float_search_space(0.0, 10.0, false);
    let obs: HashMap<String, Vec<f64>> = HashMap::new();
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    let py_w = get_f64_vec(&b, "pe_float_empty_weights");
    assert_vec_close(pe.weights(), &py_w, TOL, "pe_float_empty_weights");

    let (mus, sigmas, _, _) = pe.numerical_kernels("x").unwrap();
    let py_mus = get_f64_vec(&b, "pe_float_empty_mus");
    let py_sig = get_f64_vec(&b, "pe_float_empty_sigmas");
    assert_vec_close(&mus, &py_mus, TOL, "pe_float_empty_mus");
    assert_vec_close(&sigmas, &py_sig, TOL, "pe_float_empty_sigmas");
}

