// ═══════════════════════════════════════════════════════════════════════════
//  13. Categorical — kernel weights & log_pdf
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_pe_categorical() {
    let b = load_baseline();
    let mut ss = IndexMap::new();
    ss.insert(
        "opt".to_string(),
        Distribution::CategoricalDistribution(
            CategoricalDistribution::new(vec![
                CategoricalChoice::Str("a".into()),
                CategoricalChoice::Str("b".into()),
                CategoricalChoice::Str("c".into()),
            ])
            .unwrap(),
        ),
    );

    // Empty observation
    {
        let obs: HashMap<String, Vec<f64>> = HashMap::new();
        let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);
        let cat_w = pe.categorical_kernels("opt").unwrap();
        let py_empty: Vec<Vec<f64>> = b["pe_cat_empty_weights"]
            .as_array()
            .unwrap()
            .iter()
            .map(|row| row.as_array().unwrap().iter().map(|v| v.as_f64().unwrap()).collect())
            .collect();
        assert_eq!(cat_w.len(), py_empty.len(), "cat_empty kernel count");
        for (i, (r, p)) in cat_w.iter().zip(py_empty.iter()).enumerate() {
            assert_vec_close(r, p, TOL, &format!("cat_empty_weights[{i}]"));
        }
    }

    // With observations [0, 0, 1]
    {
        let mut obs = HashMap::new();
        obs.insert("opt".to_string(), vec![0.0, 0.0, 1.0]);
        let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

        let cat_w = pe.categorical_kernels("opt").unwrap();
        let py_obs: Vec<Vec<f64>> = b["pe_cat_obs_weights"]
            .as_array()
            .unwrap()
            .iter()
            .map(|row| row.as_array().unwrap().iter().map(|v| v.as_f64().unwrap()).collect())
            .collect();
        assert_eq!(cat_w.len(), py_obs.len(), "cat_obs kernel count");
        for (i, (r, p)) in cat_w.iter().zip(py_obs.iter()).enumerate() {
            assert_vec_close(r, p, TOL, &format!("cat_obs_weights[{i}]"));
        }

        // log_pdf
        let samples = HashMap::from([("opt".to_string(), vec![0.0, 1.0, 2.0])]);
        let rust = pe.log_pdf(&samples);
        let py = get_f64_vec(&b, "pe_cat_logpdf");
        assert_vec_close(&rust, &py, TOL, "pe_cat_logpdf");
    }
}

