// ═══════════════════════════════════════════════════════════════════════════
//  17. Close observations — sigma clipping
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_pe_close_observations() {
    let b = load_baseline();
    let ss = float_search_space(0.0, 10.0, false);
    let mut obs = HashMap::new();
    obs.insert("x".to_string(), vec![5.0, 5.0, 5.0]);
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    let (mus, sigmas, _, _) = pe.numerical_kernels("x").unwrap();
    let py_mus = get_f64_vec(&b, "pe_close_obs_mus");
    let py_sig = get_f64_vec(&b, "pe_close_obs_sigmas");
    assert_vec_close(&mus, &py_mus, TOL, "pe_close_obs_mus");
    assert_vec_close(&sigmas, &py_sig, TOL, "pe_close_obs_sigmas");

    // log_pdf should be finite
    let samples = HashMap::from([("x".to_string(), vec![4.0, 5.0, 6.0])]);
    let logpdf: Vec<f64> = pe.log_pdf(&samples);
    for v in &logpdf {
        assert!(v.is_finite(), "log_pdf should be finite for close obs");
    }
}

