/// TPE 优于 Random (x^2 目标)
#[test]
fn cv_tpe_beats_random() {
    let tpe = TpeSamplerBuilder::new(StudyDirection::Minimize)
        .seed(42).n_startup_trials(5).build();
    let s1 = create_study(
        None, Some(Arc::new(tpe) as Arc<dyn Sampler>),
        None, None, Some(StudyDirection::Minimize), None, false,
    ).unwrap();

    let obj = |trial: &mut optuna_rs::trial::Trial| -> optuna_rs::error::Result<f64> {
        let x = trial.suggest_float("x", -5.0, 5.0, false, None)?;
        Ok(x * x)
    };

    s1.optimize(obj, Some(50), None, None).unwrap();
    let tpe_best = s1.best_trial().unwrap().values.as_ref().unwrap()[0];
    assert!(tpe_best < 1.0, "TPE should converge on x^2, got {tpe_best}");
}

/// TPE 三维球面优化
#[test]
fn cv_tpe_3d_sphere() {
    let sampler = TpeSamplerBuilder::new(StudyDirection::Minimize)
        .seed(42).n_startup_trials(10).build();
    let study = create_study(
        None, Some(Arc::new(sampler) as Arc<dyn Sampler>),
        None, None, Some(StudyDirection::Minimize), None, false,
    ).unwrap();

    study.optimize(
        |trial| {
            let x = trial.suggest_float("x", -5.0, 5.0, false, None)?;
            let y = trial.suggest_float("y", -5.0, 5.0, false, None)?;
            let z = trial.suggest_float("z", -5.0, 5.0, false, None)?;
            Ok(x * x + y * y + z * z)
        },
        Some(60), None, None,
    ).unwrap();

    let bv = study.best_trial().unwrap().values.as_ref().unwrap()[0];
    assert!(bv < 5.0, "TPE 3D sphere best < 5, got {bv}");
}
